def count_shichi_go_san(N):
    from collections import deque

    count = 0
    queue = deque([''])

    while queue:
        s = queue.popleft()
        for digit in ('3', '5', '7'):
            new_s = s + digit
            if new_s == '':
                continue
            num = int(new_s)
            if num > N:
                continue
            if '3' in new_s and '5' in new_s and '7' in new_s:
                count += 1
            queue.append(new_s)

    return count

