import sys

def count_numbers_with_k_ones_up_to(x, k):
    if x <= 0:
        return 0
    res = 0
    length = x.bit_length()
    for pos in range(length - 1, -1, -1):
        if x & (1 << pos):
            remaining_pos = pos
            needed = k - 1
            if needed >= 0:
                if remaining_pos >= needed:
                    res += comb(remaining_pos, needed)
            k -= 1
            if k < 0:
                break
    if k == 0:
        res += 1
    return res

def comb(n, k):
    if k < 0 or k > n:
        return 0
    if k > n - k:
        k = n - k
    res = 1
    for i in range(1, k + 1):
        res = res * (n - i + 1) // i
    return res

def count_in_range(L, R, k):
    return count_numbers_with_k_ones_up_to(R, k) - count_numbers_with_k_ones_up_to(L - 1, k)

