def solve():
    input = sys.stdin.read
    data = input().split()
    N = int(data[0])
    A = []
    idx = 1
    for i in range(N):
        row = []
        for j in range(N):
            row.append(int(data[idx]))
            idx += 1
        A.append(row)

    # Check symmetry and diagonal zero
    for i in range(N):
        if A[i][i] != 0:
            print(-1)
            return
        for j in range(N):
            if A[i][j] != A[j][i]:
                print(-1)
                return

    # Floyd-Warshall to check triangle inequality and detect if A is indeed shortest paths
    # Actually we need to check that for every triple (i, j, k), A[i][j] <= A[i][k] + A[k][j]
    # and that there is no shorter path via other nodes.
    # But more importantly, we need to construct the graph with minimal total length.
    # The minimal graph is the one where we include an edge (i, j) only if it is necessary,
    # i.e., there is no intermediate node k such that A[i][j] == A[i][k] + A[k][j].
    # Then the total length is sum of such necessary edges.

    # First, check triangle inequality and strictness for equality cases.
    for i in range(N):
        for j in range(N):
            for k in range(N):
                if A[i][j] > A[i][k] + A[k][j]:
                    print(-1)
                    return

    total = 0
    # We'll consider each unordered pair (i, j) with i < j
    for i in range(N):
        for j in range(i+1, N):
            necessary = True
            for k in range(N):
                if k == i or k == j:
                    continue
                if A[i][j] == A[i][k] + A[k][j]:
                    necessary = False
                    break
            if necessary:
                total += A[i][j]

    print(total)

