import heapq

def solve():
    input = sys.stdin.read
    data = input().split()
    idx = 0
    n = int(data[idx]); idx += 1
    m = int(data[idx]); idx += 1

    graph = [[] for _ in range(n + 1)]
    for _ in range(m):
        a = int(data[idx]); idx += 1
        b = int(data[idx]); idx += 1
        t = int(data[idx]); idx += 1
        graph[a].append((b, t))
        graph[b].append((a, t))

    balls = []
    for _ in range(7):
        balls.append(int(data[idx])); idx += 1

    # Dijkstra from each ball city and from city 1
    ball_cities = list(set(balls))
    ball_cities.sort()
    k = len(ball_cities)
    if k > 7:
        k = 7

    # Map ball city to its index in ball_cities
    city_to_idx = {city: i for i, city in enumerate(ball_cities)}

    # dist_from_ball[i] = shortest distance from ball_cities[i] to all cities
    dist_from_ball = []
    for start in ball_cities:
        dist = [float('inf')] * (n + 1)
        dist[start] = 0
        pq = [(0, start)]
        while pq:
            d, u = heapq.heappop(pq)
            if d != dist[u]:
                continue
            for v, w in graph[u]:
                nd = d + w
                if nd < dist[v]:
                    dist[v] = nd
                    heapq.heappush(pq, (nd, v))
        dist_from_ball.append(dist)

    # Dijkstra from city 1
    dist_from_1 = [float('inf')] * (n + 1)
    dist_from_1[1] = 0
    pq = [(0, 1)]
    while pq:
        d, u = heapq.heappop(pq)
        if d != dist_from_1[u]:
            continue
        for v, w in graph[u]:
            nd = d + w
            if nd < dist_from_1[v]:
                dist_from_1[v] = nd
                heapq.heappush(pq, (nd, v))

    # DP[mask][last] = min cost to collect balls corresponding to mask,
    # ending at ball_cities[last]
    INF = 10**18
    dp = [[INF] * k for _ in range(1 << k)]
    for i in range(k):
        dp[1 << i][i] = dist_from_1[ball_cities[i]]

    for mask in range(1 << k):
        for last in range(k):
            if dp[mask][last] == INF:
                continue
            for nxt in range(k):
                if mask & (1 << nxt):
                    continue
                new_mask = mask | (1 << nxt)
                cost = dp[mask][last] + dist_from_ball[last][ball_cities[nxt]]
                if cost < dp[new_mask][nxt]:
                    dp[new_mask][nxt] = cost

    full_mask = (1 << k) - 1
    ans = min(dp[full_mask][i] for i in range(k))

    if ans >= INF // 2:
        print(-1)
    else:
        print(ans)

