    if area2(p, a, b) != 0:
        return False
    return min(a.x, b.x) <= p.x <= max(a.x, b.x) and min(a.y, b.y) <= p.y <= max(a.y, b.y)

def segments_intersect(a1, a2, b1, b2):
    o1 = sign((a2 - a1).cross(b1 - a1))
    o2 = sign((a2 - a1).cross(b2 - a1))
    o3 = sign((b2 - b1).cross(a1 - b1))
    o4 = sign((b2 - b1).cross(a2 - b1))
    if o1 != o2 and o3 != o4:
        return True
    if o1 == 0 and on_segment(b1, a1, a2):
        return True
    if o2 == 0 and on_segment(b2, a1, a2):
        return True
    if o3 == 0 and on_segment(a1, b1, b2):
        return True
    if o4 == 0 and on_segment(a2, b1, b2):
        return True
    return False

def triangle_intersection(t1, t2):
    a1, b1, c1 = t1
    a2, b2, c2 = t2
    edges1 = [(a1, b1), (b1, c1), (c1, a1)]
    edges2 = [(a2, b2), (b2, c2), (c2, a2)]
    for e1 in edges1:
        for e2 in edges2:
            if segments_intersect(e1[0], e1[1], e2[0], e2[1]):
                return True
    def point_in_triangle(p, t):
        a, b, c = t
        d1 = sign((b - a).cross(p - a))
        d2 = sign((c - b).cross(p - b))
        d3 = sign((a - c).cross(p - c))
        has_pos = (d1 > 0) or (d2 > 0) or (d3 > 0)
        has_neg = (d1 < 0) or (d2 < 0) or (d3 < 0)
        if not (has_pos and has_neg):
            return True
        return False
    if point_in_triangle(a2, t1) or point_in_triangle(b2, t1) or point_in_triangle(c2, t1):
        return True
    if point_in_triangle(a1, t2) or point_in_triangle(b1, t2) or point_in_triangle(c1, t2):
        return True
    return False

def read_triangles(n):
