        p1, p2, p3 = Point(x1, y1), Point(x2, y2), Point(x3, y3)
        if area2(p1, p2, p3) == 0:
            continue
        tris.append((p1, p2, p3))
    return tris

def build_graph(triangles):
    n = len(triangles)
    adj = [[] for _ in range(n)]
    for i in range(n):
        for j in range(i + 1, n):
            if triangle_intersection(triangles[i], triangles[j]):
                adj[i].append(j)
                adj[j].append(i)
    return adj

def dfs(u, visited, adj, component, triangles, points_map):
    stack = [u]
    while stack:
        v = stack.pop()
        if visited[v]:
            continue
        visited[v] = True
        component.append(v)
        for w in adj[v]:
            if not visited[w]:
                stack.append(w)

def canonical_form(triangles, indices):
    all_points = []
    for idx in indices:
        a, b, c = triangles[idx]
        all_points.append(a)
        all_points.append(b)
        all_points.append(c)
    min_x = min(p.x for p in all_points)
    min_y = min(p.y for p in all_points)
    translated = [Point(p.x - min_x, p.y - min_y) for p in all_points]
    return tuple(sorted((p.x, p.y) for p in translated))

