        # Count misplaced elements: positions where parity of index != parity of value
        # We need to count how many indices are "even index but odd value" (type A)
        # and how many are "odd index but even value" (type B).
        # Each swap fixes one of each type, so answer is count of mismatches of each type
        # if they are equal, otherwise impossible.
        cnt_misplaced_even = 0  # even index but odd value
        cnt_misplaced_odd = 0   # odd index but even value

        for i in range(n):
            if i % 2 != a[i] % 2:
                if i % 2 == 0:
                    cnt_misplaced_even += 1
                else:
                    cnt_misplaced_odd += 1

        if cnt_misplaced_even != cnt_misplaced_odd:
